<?php require_once __DIR__ . '/includes/functions.php'; startSecureSession(); require_once __DIR__ . '/includes/db.php'; requireAdmin($pdo); $rows = tableExists($pdo,'system_logs') ? $pdo->query('SELECT sl.*, u.name AS user_name FROM system_logs sl LEFT JOIN users u ON u.ID=sl.user_id ORDER BY sl.ID DESC LIMIT 250')->fetchAll() : []; require_once __DIR__ . '/includes/header.php'; ?>
<h1 class="title">System Logs</h1><div class="card"><div class="table-wrap"><table><thead><tr><th>Date</th><th>User</th><th>Module</th><th>Action</th><th>Details</th><th>IP</th></tr></thead><tbody><?php foreach($rows as $row): ?><tr><td><?= e((string)$row['created_at']) ?></td><td><?= e((string)$row['user_name']) ?></td><td><?= e((string)$row['module_name']) ?></td><td><?= e((string)$row['action_name']) ?></td><td><?= e((string)$row['details']) ?></td><td><?= e((string)$row['ip_address']) ?></td></tr><?php endforeach; ?></tbody></table></div></div><?php require_once __DIR__ . '/includes/footer.php'; ?>
